from typing import List, Tuple

def sum_product(numbers: List[int]) -> Tuple[int,int]:
    sum_numbers = sum(numbers)
    product_numbers = 1
    for num in numbers:
        product_numbers *= num
    return (sum_numbers, product_numbers)

def is_palindrome(string:str)->bool:
    """Testifgivenstringisapalindrome"""
    return string==string[::-1]

def make_palindrome(string:str)->str:
    """Findtheshortestpalindromethatbeginswithasuppliedstring.Algorithmideaissimple:-Findthelongestpostfixofsuppliedstringthatisapalindrome.-Appendtotheendofthestringreverseofastringprefixthatcomesbeforethepalindromicsuffix."""
    for i in range(len(string)):
        if is_palindrome(string[i:]):
            return string + string[:i][::-1]

