def parse_music(music_string: str) -> List[int]:
    notes = music_string.split('|')
    result = []
    for note in notes:
        if note == 'o':
            result.append(4)
        elif note == '.':
            result.append(2)
        elif note == '|':
            result.append(1)
    return result

