def prime_fib(n: int) -> int:
    def is_prime(num: int) -> bool:
        if num < 2:
            return False
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                return False
        return True

    def fib(n: int) -> int:
        if n <= 1:
            return n
        a, b = 0, 1
        for _ in range(n - 1):
            a, b = b, a + b
        return b

    i = 0
    while True:
        fib_num = fib(i)
        if fib_num > n:
            return fib_num - 1
        if is_prime(fib_num):
            return fib_num
        i += 1

