def triples_sum_to_zero(l):
    hash_map = {}
    for i in range(len(l)):
        for j in range(i+1, len(l)):
            complement = -(l[i] + l[j])
            if complement in hash_map:
                return True
            else:
                hash_map[l[j]] = True
    return False

def car_race_collision(n:int):
    # Create a list of cars
    cars = [(1, 'left')] + [(1, 'right')]*(n-1)

    # Initialize a counter for collisions
    collisions = 0

    # Iterate over the list of cars
    for i in range(len(cars)):
        for j in range(i+1, len(cars)):
            # Check for collision
            if cars[i][0] == cars[j][0] and cars[i][1] == cars[j][1]:
                collisions += 1

    return collisions

def pairs_sum_to_zero(l):
    # Create an empty dictionary
    num_dict = {}

    # Iterate over the list
    for num in l:
        # Check if the number is already in the dictionary
        if num in num_dict:
            # If it is, return True
            return True
        else:
            # If it's not, add it to the dictionary
            num_dict[abs(num)] = num

    # If we've gone through the entire list without finding a pair that sums to zero, return False
    return False

def change_base(x: int, base: int) -> str:
    if x < base:
        return str(x)
    else:
        return change_base(x // base, base) + str(x % base)

def fib4(n: int) -> int:
    if n == 0:
        return 0
    elif n == 1 or n == 2:
        return 0
    elif n == 3:
        return 2
    else:
        fib = [0, 0, 2, 0]
        for i in range(4, n + 1):
            fib.append(fib[i-1] + fib[i-2] + fib[i-3] + fib[i-4])
        return fib[n]

def median(l: list):
    l.sort()
    n = len(l)
    if n % 2 == 0:
        return (l[n//2 - 1] + l[n//2]) / 2
    else:
        return l[n//2]

