def encode_shift(s:str):
    """Returns encoded string by shifting every character by 5 in the alphabet."""
    return "".join([chr(((ord(ch)+5-ord("a"))%26)+ord("a"))forch in s])

def decode_shift(s:str):
    """Takes an input string encoded with the encode_shift function. Returns decoded string."""
    return "".join([chr(((ord(ch)-5-ord("a"))%26)+ord("a"))forch in s])

