def smallest_change(arr):
    changes = 0
    while arr[0] != arr[-1]:
        if arr[0] < arr[-1]:
            arr[0] += 1
            changes += 1
        else:
            arr[-1] -= 1
            changes += 1
    return changes

def total_match(lst1, lst2):
    if len(lst1) == 0 and len(lst2) == 0:
        return []
    elif len(lst1) == 0:
        return lst2
    elif len(lst2) == 0:
        return lst1
    else:
        sum1 = sum(len(i) for i in lst1)
        sum2 = sum(len(i) for i in lst2)
        if sum1 <= sum2:
            return lst1
        else:
            return lst2

def is_multiply_prime(a):
    def is_prime(n):
        if n < 2:
            return False
        for i in range(2, int(n**0.5) + 1):
            if n % i == 0:
                return False
        return True

    primes = [i for i in range(2, a) if is_prime(i)]
    for i in range(len(primes)):
        for j in range(i + 1, len(primes)):
            for k in range(j + 1, len(primes)):
                if primes[i] * primes[j] * primes[k] == a:
                    return True
    return False

