def encode(message):
    vowels = 'aeiou'
    encoded_message = ''
    for char in message:
        if char.lower() in vowels:
            index = vowels.index(char.lower())
            if index < 2:
                encoded_message += char
            else:
                encoded_message += chr(ord(char) + 2)
        else:
            encoded_message += char
    return encoded_message

