def multiply(a, b):
    product = 0
    a_str = str(abs(a))
    b_str = str(abs(b))
    for digit_a in a_str:
        for digit_b in b_str:
            product += int(digit_a) * int(digit_b)
    return product

def closest_integer(value):
    value = float(value)
    if value >= 0:
        return int(value + 0.5) if value - int(value) >= 0.5 else int(value)
    else:
        return int(value - 0.5) if abs(value - int(value)) >= 0.5 else int(value)

