def move_one_ball(arr):
    if len(arr) == 0:
        return True

    count = 0
    for i in range(len(arr)):
        if arr[i] < arr[i + 1]:
            count += 1

    if count == 0:
        return True
    elif count == 1:
        return False
    else:
        return False

