print(move_one_ball([1, 2, 3, 4, 5]))  # True
print(move_one_ball([5, 4, 3, 2, 1]))  # True
print(move_one_ball([1, 2, 3, 5, 4]))  # False
print(move_one_ball([1]))  # True
