def minSubArraySum(nums):
    if not nums:
        return 0

    min_sum = float('inf')
    cur_sum = 0

    for num in nums:
        cur_sum += num
        if cur_sum < min_sum:
            min_sum = cur_sum
        if cur_sum > 0:
            cur_sum = 0

    return min_sum

# Test cases
print(minSubArraySum([2,3,4,1,2,4])) # 1
print(minSubArraySum([-1,-2,-3])) # -6

