            result.append(word)
    return result

def match_parens(lst):
    def is_balanced(s):
        count = 0
        for char in s:
            if char == '(':
                count += 1
            elif char == ')':
                count -= 1
            if count < 0:
                return False
        return count == 0

    s1 = lst[0] + lst[1]
    s2 = lst[1] + lst[0]
    return 'Yes' if is_balanced(s1) or is_balanced(s2) else 'No'

print(match_parens(['()(', ')']))
print(match_parens([')', ')']))

