def get_odd_collatz(n):
    sequence = [n]
    while n != 1:
        if n % 2 == 0:
            n = n // 2
        else:
            n = 3 * n + 1
        sequence.append(n)
    return sorted(filter(lambda x: x % 2 != 0, sequence))

def valid_date(date):
    # Split the date string into day, month, and year
    day, month, year = map(int, date.split('-'))

    # Check if the date string is in the correct format
    if len(date) != 10 or month < 1 or month > 12 or day < 1 or day > 31:
        return False

    # Check if the month has 31 days
    if month in [1, 3, 5, 7, 8, 10, 12]:
        if day > 31:
            return False
    # Check if the month has 30 days
    elif month in [4, 6, 9, 11]:
        if day > 30:
            return False
    # Check if the month has 29 days
    elif month == 2:
        if day > 29:
            return False
    # Check if the year is a leap year
    if year % 4 == 0 and (year % 100 != 0 or year % 400 == 0):
        if day > 29:
            return False
    return True

def split_words(txt):
    if ',' in txt:
        return txt.replace(',', '').split()
    elif '!' in txt:
        return txt.replace('!', '').split()
    else:
        return [word for word in txt.split() if word.islower() and (ord(word[0]) - ord('a')) % 2 == 1]

def intersection(interval1, interval2):
    start = max(interval1[0], interval2[0])
    end = min(interval1[1], interval2[1])

    if start > end:
        return "NO"
    else:
        return "YES" if start == end else "NO"

