def prod_signs(arr):
    if not arr:
        return None
    sign = 1
    product = 1
    for num in arr:
        if num < 0:
            sign *= -1
        product *= abs(num)
    return sign * product

def tribonacci(n):
    if n == 0:
        return [0]
    elif n == 1:
        return [0, 0, 1]
    elif n == 2:
        return [0, 1, 1]
    else:
        sequence = [0, 0, 1]
        for i in range(3, n + 1):
            if i % 2 == 0:
                sequence.append(sequence[i - 1] + sequence[i - 2] + sequence[i - 3])
            else:
                sequence.append(sequence[i - 1] + sequence[i - 2] + sequence[i - 3] + 1)
        return sequence

# Test cases
print(tribonacci(3))  # [0, 0, 1, 1, 2, 4, 7]
print(tribonacci(5))  # [0, 0, 1, 1, 2, 4, 7, 13, 24, 44, 72, 126]

def digits(n):
    product = 1
    for digit in str(n):
        if int(digit) % 2 != 0:
            product *= int(digit)
    return product

