def compare_one(a, b):
    if isinstance(a, (int, float, str)) and isinstance(b, (int, float, str)):
        if isinstance(a, str):
            a = float(a.replace(',', '.'))
        if isinstance(b, str):
            b = float(b.replace(',', '.'))
        return a - b
    else:
        return None

