def is_equal_to_sum_even(n):
    if n < 4:
        return False
    for i in range(2, n, 2):
        if n - i == 4:
            return True
    return False

def special_factorial(n):
    def factorial(n):
        if n == 0:
            return 1
        else:
            return n * factorial(n-1)
    return factorial(n) * factorial(n-1) * factorial(n-2) * ... * factorial(1)

