def simplify(x, n):
    def is_valid_fraction(s):
        try:
            num, den = map(int, s.split('/'))
            return num > 0 and den > 0
        except ValueError:
            return False

    if not is_valid_fraction(x) or not is_valid_fraction(n):
        return False

    x_num, x_den = map(int, x.split('/'))
    n_num, n_den = map(int, n.split('/'))

    common_denominator = x_den * n_den
    new_numerator = x_num * n_den - x_den * n_num

    return new_numerator / common_denominator == 1

def order_by_points(nums):
    def sum_of_digits(n):
        return sum(int(digit) for digit in str(n))

    return sorted(nums, key=sum_of_digits)

