def double_the_difference(lst):
    sum_of_squares = 0
    for num in lst:
        if num >= 0 and num % 2 != 0:
            sum_of_squares += num ** 2
    return sum_of_squares

def compare(game, guess):
    result = []
    for i in range(len(game)):
        if game[i] == guess[i]:
            result.append(0)
        elif game[i] in guess:
            result.append(1)
        else:
            result.append(-1)
    return result

