def cycpattern_check(a, b):
    # Create all rotations of a
    rotations = [a[i:] + a[:i] for i in range(len(a))]

    # Check if any of the rotations is a substring of b
    for rotation in rotations:
        if rotation in b:
            return True

    # If no rotation is a substring of b, return False
    return False

def even_odd_count(num):
    even_count = 0
    odd_count = 0
    for digit in str(num):
        if int(digit) % 2 == 0:
            even_count += 1
        else:
            odd_count += 1
    return (even_count, odd_count)

