print(defeat(4, 8, 9))  # [12, 1]
print(defeat(1, 10, 10))  # [11, 0]
print(defeat(2, 11, 5))  # [7, 0]

def do_algebra(operator, operand):
    result = operand[0]
    for i in range(1, len(operand)):
        if operator[i-1] == '+':
            result += operand[i]
        elif operator[i-1] == '-':
            result -= operand[i]
        elif operator[i-1] == '*':
            result *= operand[i]
        elif operator[i-1] == '//':
            result //= operand[i]
        elif operator[i-1] == '**':
            result **= operand[i]
    return result

# Test the function
print(do_algebra(['+', '*', '-'], [2, 3, 4, 5]))  # Output: 9

def solve(s):
    if s.isalpha():
        if s.islower():
            return s.swapcase()
        else:
            return s.swapcase()
    else:
        return s[::-1]

print(solve("1234"))  # Output: "4321"
print(solve("ab"))  # Output: "AB"
print(solve("#a@C"))  # Output: "#A@c"

import hashlib

def string_to_md5(text):
    if text == '':
        return None
    return hashlib.md5(text.encode()).hexdigest()
